```go
package api_test

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/go-chi/chi/v5"
	"github.com/stretchr/testify/require"

	"beanbrew/internal/api"
	"beanbrew/internal/api/helpers"
	"beanbrew/internal/domain"
	"beanbrew/internal/infrastructure"
	"beanbrew/internal/repository/sqlite"
	"beanbrew/internal/usecase"
)

// ---------------------------------------------------------------------------
// Helper structs that mirror the request payloads used by the API
// ---------------------------------------------------------------------------
type categoryReq struct {
	Name        string `json:"name"`
	Slug        string `json:"slug"`
	Description string `json:"description,omitempty"`
	SortOrder   int    `json:"sort_order,omitempty"`
}

type productReq struct {
	CategoryID int64   `json:"category_id"`
	Name       string  `json:"name"`
	Description string `json:"description,omitempty"`
	Price      float64 `json:"price"`
	ImageURL   string  `json:"image_url,omitempty"`
	InStock    bool    `json:"in_stock,omitempty"`
}

type orderReq struct {
	CustomerID string               `json:"customer_id"`
	Items      []orderItemReq      `json:"items"`
}

type orderItemReq struct {
	ProductID int64   `json:"product_id"`
	Quantity  int     `json:"quantity"`
	Price     float64 `json:"price,omitempty"` // ignored by the API – set by use‑case
}

// ---------------------------------------------------------------------------
// Test: full end‑to‑end flow (category → product → order → process → complete)
// ---------------------------------------------------------------------------
func TestAPIOrderFullFlowWithCategoryAndProduct(t *testing.T) {
	// 1. Spin up a fresh in‑memory server – every test gets its own DB.
	srv := setupTestServer(t) // defined in testhelper_test.go
	defer srv.Close()

	// -----------------------------------------------------------------------
	// 1️⃣  Create a category (required for the product)
	// -----------------------------------------------------------------------
	catPayload := categoryReq{
		Name: "Кофе",
		Slug: "coffee",
	}
	catResp := postJSON(t, srv.URL+"/categories", catPayload)
	require.Equal(t, http.StatusCreated, catResp.Code)

	var catCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, catResp.Body, &catCreated)
	require.Greater(t, catCreated.ID, int64(0), "category ID must be > 0")

	// -----------------------------------------------------------------------
	// 2️⃣  Create a product that belongs to the newly created category
	// -----------------------------------------------------------------------
	prodPayload := productReq{
		CategoryID: catCreated.ID,
		Name:       "Латте",
		Price:      350.0,
		InStock:    true,
	}
	prodResp := postJSON(t, srv.URL+"/products", prodPayload)
	require.Equal(t, http.StatusCreated, prodResp.Code)

	var prodCreated struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, prodResp.Body, &prodCreated)
	require.Greater(t, prodCreated.ID, int64(0), "product ID must be > 0")

	// -----------------------------------------------------------------------
	// 3️⃣  Create an order that uses the product we just created
	// -----------------------------------------------------------------------
	orderPayload := orderReq{
		CustomerID: "alice@example.com",
		Items: []orderItemReq{
			{
				ProductID: prodCreated.ID,
				Quantity:  2,
			},
		},
	}
	orderResp := postJSON(t, srv.URL+"/orders", orderPayload)
	require.Equal(t, http.StatusCreated, orderResp.Code)

	var orderCreated struct {
		ID        int64   `json:"id"`
		Total     float64 `json:"total"`
		Status    string  `json:"status"`
		CreatedAt string  `json:"created_at"` // ISO‑8601 string – we only check existence
	}
	decodeBody(t, orderResp.Body, &orderCreated)

	// The use‑case must have set the price from the product (350) and calculated
	// the total = 350 * 2 = 700.
	require.Equal(t, float64(700), orderCreated.Total)
	require.Equal(t, string(domain.OrderStatusNew), orderCreated.Status)

	// -----------------------------------------------------------------------
	// 4️⃣  Process the order (new → processing)
	// -----------------------------------------------------------------------
	processResp := doPost(t, srv.URL+"/orders/"+int64ToStr(orderCreated.ID)+"/process")
	require.Equal(t, http.StatusOK, processResp.Code)

	// Verify the status after processing
	getAfterProcess := doGet(t, srv.URL+"/orders/"+int64ToStr(orderCreated.ID))
	require.Equal(t, http.StatusOK, getAfterProcess.Code)

	var orderAfterProcess struct {
		Status string `json:"status"`
	}
	decodeBody(t, getAfterProcess.Body, &orderAfterProcess)
	require.Equal(t, string(domain.OrderStatusProcessing), orderAfterProcess.Status)

	// -----------------------------------------------------------------------
	// 5️⃣  Complete the order (processing → completed)
	// -----------------------------------------------------------------------
	completeResp := doPost(t, srv.URL+"/orders/"+int64ToStr(orderCreated.ID)+"/complete")
	require.Equal(t, http.StatusOK, completeResp.Code)

	// Final verification – the order must be in the *completed* state
	getAfterComplete := doGet(t, srv.URL+"/orders/"+int64ToStr(orderCreated.ID))
	require.Equal(t, http.StatusOK, getAfterComplete.Code)

	var orderAfterComplete struct {
		Status string `json:"status"`
	}
	decodeBody(t, getAfterComplete.Body, &orderAfterComplete)
	require.Equal(t, string(domain.OrderStatusCompleted), orderAfterComplete.Status)
}

// ---------------------------------------------------------------------------
// Utility wrappers used only in this file (they delegate to the helpers in
// testhelper_test.go but keep the test self‑contained and readable)
// ---------------------------------------------------------------------------
func postJSON(t *testing.T, url string, payload any) *httptest.ResponseRecorder {
	body, err := json.Marshal(payload)
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, url, jsonReader(body))
	req.Header.Set("Content-Type", "application/json")
	rr := httptest.NewRecorder()
	chi.NewRouter().ServeHTTP(rr, req) // dummy router – the real handler is attached in setupTestServer
	// The real request is sent through the server created by setupTestServer:
	resp, err := http.DefaultClient.Do(req)
	require.NoError(t, err)
	defer resp.Body.Close()
	rr.Result().Header = resp.Header
	rr.Result().StatusCode = resp.StatusCode
	rr.Body = &nopReadCloser{Reader: resp.Body}
	return rr
}

func doPost(t *testing.T, url string) *httptest.ResponseRecorder {
	req := httptest.NewRequest(http.MethodPost, url, nil)
	rr := httptest.NewRecorder()
	resp, err := http.DefaultClient.Do(req)
	require.NoError(t, err)
	defer resp.Body.Close()
	rr.Result().Header = resp.Header
	rr.Result().StatusCode = resp.StatusCode
	rr.Body = &nopReadCloser{Reader: resp.Body}
	return rr
}

func doGet(t *testing.T, url string) *httptest.ResponseRecorder {
	req := httptest.NewRequest(http.MethodGet, url, nil)
	rr := httptest.NewRecorder()
	resp, err := http.DefaultClient.Do(req)
	require.NoError(t, err)
	defer resp.Body.Close()
	rr.Result().Header = resp.Header
	rr.Result().StatusCode = resp.StatusCode
	rr.Body = &nopReadCloser{Reader: resp.Body}
	return rr
}

func int64ToStr(i int64) string { return json.Number(i).String() }

type nopReadCloser struct {
	Reader http.Response.Body
}

func (n *nopReadCloser) Read(p []byte) (int, error) { return n.Reader.Read(p) }
func (n *nopReadCloser) Close() error               { return nil }

func jsonReader(b []byte) *nopReadCloser { return &nopReadCloser{Reader: http.NoBody} }
```

