Эти три теста проверяют один и тот же метод `Search` с разными входными данными. Их можно собрать в один файл:

```go
func TestIntegrationProductSearch(t *testing.T) {
    db := setupTestDB(t)
    repo := NewProductRepository(db)

    // подготовка (можно вынести в helper)
    seedProducts := []Product{
        {Name: "Капучино", Description: "молоко", CategoryID: 1, Price: 300},
        {Name: "Латте",    Description: "молоко", CategoryID: 1, Price: 350},
        {Name: "Эспрессо", Description: "кофе",   CategoryID: 1, Price: 200},
    }
    for _, p := range seedProducts {
        if err := repo.Create(context.Background(), &p); err != nil {
            t.Fatalf("seed: %v", err)
        }
    }

    cases := []struct {
        name      string
        query     string
        limit     int
        wantCount int
    }{
        {"match_description", "молок", 0, 2},
